const items = $input.all();
const postResponse = items[0]?.json || {};
const imageResponse = items[1]?.json || {};

let rawContent = postResponse.message?.content || postResponse.text || '';

// Split post and hashtags
let postText = rawContent;
let hashtags = '';

if (rawContent.includes('---')) {
  const parts = rawContent.split('---');
  postText = parts[0].trim();

  // Find hashtags section
  for (let i = 1; i < parts.length; i++) {
    if (parts[i].toLowerCase().includes('hashtag')) {
      hashtags = parts[i].replace(/hashtags?:?/gi, '').trim();
      break;
    }
  }
}

// Clean up any remaining artifacts
postText = postText.replace(/^(Here's the post:|Post:|LinkedIn Post:)/gi, '').trim();

// Extract image URL from Reve AI
let imageUrl = '';
if (!imageResponse.error && imageResponse.data && Array.isArray(imageResponse.data) && imageResponse.data[0]) {
  imageUrl = imageResponse.data[0].url || '';
}
if (!imageUrl) {
  imageUrl = imageResponse.url || imageResponse.image_url || imageResponse.output?.url || '';
}
if (imageUrl && typeof imageUrl === 'string') {
  imageUrl = imageUrl.trim();
  if (!imageUrl.startsWith('http')) imageUrl = '';
}

return [{
  json: {
    postText: postText,
    hashtags: hashtags,
    imageUrl: imageUrl,
    hasValidImage: !!(imageUrl && imageUrl.length > 10)
  }
}];

const downloadedImage = $input.first();
const preparedPost = $('Prepare Viral Post').item.json;

if (downloadedImage.binary && Object.keys(downloadedImage.binary).length > 0) {
  return [{
    json: {
      postText: preparedPost.postText,
      hashtags: preparedPost.hashtags
    },
    binary: downloadedImage.binary
  }];
} else {
  return [{
    json: {
      postText: preparedPost.postText,
      hashtags: preparedPost.hashtags
    }
  }];
}

